#include <stdio.h>
#include <string.h>

int main() {
    char str1[50] = "Hello";
    char str2[50] = "World";
    char str3[50];

    // strlen - find length
    printf("Length of str1: %d\n", strlen(str1));

    // strcpy - copy string
    strcpy(str3, str1);
    printf("Copied: %s\n", str3);

    // strcat - concatenate
    strcat(str1, str2);
    printf("Concatenated: %s\n", str1);

    // strcmp - compare
    int result = strcmp("Apple", "Banana");
    if(result < 0)
        printf("Apple < Banana\n");
    else if(result > 0)
        printf("Apple > Banana\n");
    else
        printf("Equal\n");

    return 0;
}

#include <stdio.h>
#include <stdlib.h>

int main() {
    int n, i;
    int *arr;

    printf("Enter number of elements: ");
    scanf("%d", &n);

    // Allocate memory using malloc
    arr = (int*)malloc(n * sizeof(int));

    // Check if allocation succeeded
    if(arr == NULL) {
        printf("Memory allocation failed!\n");
        return 1;
    }

    // Accept elements
    printf("Enter %d numbers:\n", n);
    for(i = 0; i < n; i++) {
        scanf("%d", &arr[i]);
    }

    // Display elements
    printf("Array elements: ");
    for(i = 0; i < n; i++) {
        printf("%d ", arr[i]);
    }

    // Free allocated memory
    free(arr);
    arr = NULL; // Good practice

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <time.h>

int main() {
    int i, num;

    // Seed the random number generator with current time
    srand(time(NULL));

    // Generate 10 random numbers between 1 and 100
    printf("10 Random numbers between 1-100:\n");
    for(i = 0; i < 10; i++) {
        num = rand() % 100 + 1;
        printf("%d ", num);
    }

    printf("\n\nGenerating with fixed seed (5):\n");
    // Same sequence every time with fixed seed
    srand(5);
    for(i = 0; i < 5; i++) {
        num = rand() % 100 + 1;
        printf("%d ", num);
    }

    return 0;
}

#include <stdio.h>
#include <ctype.h>

int main() {
    char ch;

    printf("Enter a character: ");
    scanf("%c", &ch);

    // Classification functions (return non-zero if true)
    printf("\nCharacter Analysis:\n");
    printf("Is alphabetic? %d\n", isalpha(ch));
    printf("Is digit? %d\n", isdigit(ch));
    printf("Is alphanumeric? %d\n", isalnum(ch));
    printf("Is lowercase? %d\n", islower(ch));
    printf("Is uppercase? %d\n", isupper(ch));
    printf("Is whitespace? %d\n", isspace(ch));

    // Conversion functions
    printf("\nConversions:\n");
    printf("Uppercase: %c\n", toupper(ch));
    printf("Lowercase: %c\n", tolower(ch));

    // Practical use: convert string to uppercase
    char str[] = "Hello World";
    for(int i = 0; str[i]; i++) {
        str[i] = toupper(str[i]);
    }
    printf("\nString to uppercase: %s\n", str);

    return 0;
}
